INSERT INTO public.quiz_questions (category, language, question, options, correct_option) VALUES ('aiesec', 'en', 'Overall, what is the primary purpose of both the AIESEC Way and the Compendium?', '["To increase membership fees", "To guide AIESEC''s purpose, values, and internal rules to ensure coherent, ethical, and value-driven action", "To replace national laws", "To serve only as a marketing tool"]'::jsonb, 1);
